const DEFAULT_ANALYSIS_ERROR = "Analysis failed. Please try again.";

function getPlatformMeta(platformId) {
  return ALL_PLATS.find((p) => p.id === platformId) || ALL_PLATS[2];
}

function clamp(n, min, max) {
  return Math.max(min, Math.min(max, n));
}

function getScoreColor(score) {
  if (score >= 7) return "#4CAF50";
  if (score >= 5) return "#FFB74D";
  return R;
}

function revokePreviewUrls(items = []) {
  items.forEach((item) => {
    try {
      if (item?.url) URL.revokeObjectURL(item.url);
    } catch {
      // ignore revoke failures
    }
  });
}

