function buildViewDataFromAnalysis(analysis, { isDemo = false, uploadedPreviews = [] } = {}) {
  if (!analysis) return null;

  const freeReport = analysis.free_report || {};
  const proReport = analysis.pro_report || {};
  const breakdown = analysis.breakdown || {};
  const platformMeta = getPlatformMeta(analysis?.profile?.platform || analysis?.platform || (isDemo ? JAKE.platform : "hinge"));
  const photoBreakdown = (proReport.photo_breakdown || []).map((item, idx) => ({
    ...item,
    label: item.label || `Photo ${idx + 1}`,
    score: typeof item.score === "number" ? item.score : 0,
    scoreColor: getScoreColor(typeof item.score === "number" ? item.score : 0),
  }));

  const topPhoto = photoBreakdown.find((item) => item.score >= 7);
  const weakestPhoto = [...photoBreakdown].sort((a, b) => a.score - b.score)[0];

  const strengthList = [
    freeReport.headline,
    topPhoto ? `${topPhoto.label}: ${topPhoto.note}` : null,
  ].filter(Boolean).slice(0, 2);

  const weaknessList = [
    weakestPhoto ? `${weakestPhoto.label}: ${weakestPhoto.note}` : null,
    (analysis.notes || []).find((note) => /upload|specific|detail|solo photo|stronger/i.test(note || "")),
  ].filter(Boolean).slice(0, 2);

  const previewScores = (freeReport.photo_scores_preview || []).map((item, idx) => ({
    ...item,
    label: item.label || `Photo ${idx + 1}`,
    score: typeof item.score === "number" ? item.score : 0,
    color: getScoreColor(typeof item.score === "number" ? item.score : 0),
  }));

  const promptPreview = (freeReport.openers_preview || []).map((item) => ({
    prompt: item.prompt || "Opener",
    text: item.text || "",
  }));

  const photos = isDemo
    ? JAKE.photos.map((photo, idx) => {
        const match = photoBreakdown[idx];
        return {
          ...photo,
          label: match?.label || photo.label,
          score: match?.score ?? photo.score,
          scoreColor: match?.scoreColor || photo.scoreColor,
          desc: match?.note || photo.desc,
          note: match?.note || photo.desc,
        };
      })
    : uploadedPreviews.map((item, idx) => {
        const match = photoBreakdown[idx];
        return {
          label: match?.label || `Photo ${idx + 1}`,
          img: item.url,
          desc: item.name,
          score: match?.score ?? previewScores[idx]?.score ?? clamp((breakdown.photo_quality || freeReport.score || 6), 0, 10),
          scoreColor: match?.scoreColor || previewScores[idx]?.color || getScoreColor(breakdown.photo_quality || freeReport.score || 6),
          note: match?.note || item.name,
        };
      });

  const lookingFor = (proReport.looking_for_tags || []).map((tag) => ({
    emoji: tag.emoji || "✨",
    label: tag.label || "Interesting",
  }));

  return {
    analysisId: analysis.analysis_id,
    platformMeta,
    free: {
      dqScore: typeof freeReport.score === "number" ? freeReport.score : analysis.dq_score || 0,
      verdict: analysis.verdict || ((freeReport.score || 0) >= 6.8 ? "Promising" : "Needs Work"),
      breakdown: {
        photoQuality: breakdown.photo_quality || 0,
        bioStrength: breakdown.bio_strength || 0,
        profileEnergy: breakdown.profile_energy || 0,
        platformFit: breakdown.platform_fit || 0,
      },
      whoYouAttract: proReport.target_audience || "This profile currently attracts people who respond best to specific plans and clear personality signals.",
      strengths: strengthList.length ? strengthList : ["There is enough signal here to build a stronger profile."],
      weaknesses: weaknessList.length ? weaknessList : ["The profile still needs more specificity to stand out."],
      quickFix: weakestPhoto?.action || analysis.notes?.[3] || "Make your first photo clearer and give people one concrete detail to reply to.",
      platformNote: freeReport.hinge_tip || analysis.notes?.[2] || PLATFORM_TIPS[platformMeta.id],
      headline: freeReport.headline || "Solid foundation, but still too generic in key places.",
      bioBefore: freeReport.bio_before || "",
      bioAfterPreview: freeReport.bio_after_preview || proReport.bio_rewrite || "",
      photoScoresPreview: previewScores,
      openersPreview: promptPreview,
      projectedScore: freeReport.projected_score || proReport.projected_score || clamp((freeReport.score || 0) + 0.9, 0, 10),
    },
    pro: {
      jakeLookingFor: lookingFor,
      bioRewrite: proReport.bio_rewrite || "",
      openers: (proReport.openers || []).map((item) => ({ prompt: item.prompt || "Opener", text: item.text || "" })),
      photoBreakdown,
      targetAudience: proReport.target_audience || "",
      projectedScore: proReport.projected_score || freeReport.projected_score || clamp((freeReport.score || 0) + 0.9, 0, 10),
    },
    photos,
  };
}


