/* ─── HOOKS ───────────────────────────────────────────────────────────── */
function useCountUp(target, duration = 1300, active = true) {
  const [v, setV] = useState(0);
  useEffect(() => {
    if (!active) return;
    let start, id;
    const tick = (ts) => {
      if (!start) start = ts;
      const p = Math.min((ts - start) / duration, 1);
      setV(target * (1 - Math.pow(1 - p, 3)));
      if (p < 1) id = requestAnimationFrame(tick);
    };
    id = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(id);
  }, [target, duration, active]);
  return v;
}

/* ─── SCORE RING ──────────────────────────────────────────────────────── */
function ScoreRing({ score, size = 130 }) {
  const v = useCountUp(score, 1400);
  const c = score >= 7 ? "#4CAF50" : score >= 5 ? "#FFB74D" : R;
  return (
    <div style={{
      width: size, height: size, borderRadius: "50%", flexShrink: 0,
      background: `conic-gradient(${c} ${(v / 10) * 360}deg, rgba(255,255,255,0.06) 0deg)`,
      boxShadow: `0 0 50px ${c}28`,
      display: "flex", alignItems: "center", justifyContent: "center",
    }}>
      <div style={{
        width: size - 24, height: size - 24, borderRadius: "50%", background: CARD,
        display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
      }}>
        <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: size * 0.29, lineHeight: 1, color: c }}>{v.toFixed(1)}</div>
        <div style={{ fontSize: 8, letterSpacing: 2, textTransform: "uppercase", color: "rgba(255,255,255,0.3)", marginTop: 1 }}>DQ Score</div>
      </div>
    </div>
  );
}

/* ─── METRIC BAR ──────────────────────────────────────────────────────── */
function Bar({ label, value, color, delay = 0 }) {
  const v = useCountUp(value ?? 0, 1200 + delay);
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 11 }}>
      <div style={{ width: 100, fontSize: 12, color: "rgba(255,255,255,0.4)", flexShrink: 0 }}>{label}</div>
      <div style={{ flex: 1, height: 4, borderRadius: 99, background: "rgba(255,255,255,0.06)", overflow: "hidden" }}>
        <div style={{ height: "100%", width: `${(v / 10) * 100}%`, background: color, borderRadius: 99 }} />
      </div>
      <div style={{ width: 28, textAlign: "right", fontSize: 12, fontWeight: 700 }}>{(value ?? 0).toFixed(1)}</div>
    </div>
  );
}

/* ─── PHOTO TILE ──────────────────────────────────────────────────────── */
function PhotoTile({ ph, showScore, i }) {
  return (
    <div style={{ borderRadius: 12, overflow: "hidden", border: "1px solid rgba(255,255,255,0.07)" }}>
      <div style={{
        aspectRatio: "3/4", position: "relative", background: "#111",
        overflow: "hidden",
      }}>
        <img
          src={ph.img}
          alt={ph.label}
          style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
        />
        {i === 0 && <div style={{ position: "absolute", bottom: 6, left: 6, background: R, color: "#fff", fontSize: 7, fontWeight: 800, padding: "2px 7px", borderRadius: 99, letterSpacing: 1 }}>MAIN</div>}
        {showScore && <div style={{ position: "absolute", top: 6, right: 6, background: `${ph.scoreColor}22`, border: `1px solid ${ph.scoreColor}55`, color: ph.scoreColor, fontSize: 10, fontWeight: 800, padding: "2px 7px", borderRadius: 6 }}>{ph.score.toFixed(1)}</div>}
      </div>
      <div style={{ padding: "6px 8px", background: "rgba(0,0,0,0.3)", borderTop: "1px solid rgba(255,255,255,0.05)" }}>
        <div style={{ fontSize: 9, color: "rgba(255,255,255,0.3)" }}>{ph.label}</div>
      </div>
    </div>
  );
}

/* ─── SHARED CARD ─────────────────────────────────────────────────────── */
function SCard({ children, style }) {
  return (
    <div style={{ background: CARD, border: "1px solid rgba(245,197,163,0.07)", borderRadius: 18, padding: "18px 16px", marginBottom: 10, ...style }}>
      {children}
    </div>
  );
}
function SLabel({ children, color }) {
  return <div style={{ fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: color || BLUSH, fontWeight: 700, marginBottom: 10 }}>{children}</div>;
}

