/* ════════════════════════════════════════════════════════════════════════
   SCREEN 3 — LOADING
════════════════════════════════════════════════════════════════════════ */
function Loading({ ready, onDone }) {
  const [active, setActive] = useState(0);
  const [complete, setComplete] = useState(false);

  useEffect(() => {
    const timer = setInterval(() => {
      setActive((prev) => (ready ? Math.min(prev + 1, STEPS.length - 1) : (prev + 1) % STEPS.length));
    }, 520);
    return () => clearInterval(timer);
  }, [ready]);

  useEffect(() => {
    if (!ready || complete) return undefined;
    const timer = setTimeout(() => setComplete(true), 500);
    return () => clearTimeout(timer);
  }, [ready, complete]);

  useEffect(() => {
    if (!complete) return undefined;
    const timer = setTimeout(onDone, 650);
    return () => clearTimeout(timer);
  }, [complete, onDone]);

  return (
    <div style={{ textAlign: "center", padding: "56px 0" }}>
      <div style={{ position: "relative", width: 72, height: 72, margin: "0 auto 28px" }}>
        <div style={{
          width: 72, height: 72, borderRadius: "50%",
          border: "2.5px solid rgba(255,71,87,0.12)", borderTopColor: complete ? "#4CAF50" : R,
          animation: complete ? "none" : "spin .85s linear infinite", position: "absolute", inset: 0,
          transition: "border-top-color .4s",
        }} />
        <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26 }}>
          {complete ? "✓" : STEPS[active]?.icon}
        </div>
      </div>

      <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 26, letterSpacing: 3, marginBottom: 28, color: complete ? "#4CAF50" : "#fff", transition: "color .4s" }}>
        {complete ? "Analysis Complete" : "Analyzing Profile"}
      </div>

      <div style={{ maxWidth: 300, margin: "0 auto" }}>
        {STEPS.map((s, i) => (
          <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, padding: "7px 0", opacity: i <= active ? 1 : 0.15, transition: "opacity .35s" }}>
            <div style={{
              width: 18, height: 18, borderRadius: "50%", flexShrink: 0,
              background: i < active || complete ? "#4CAF5018" : i === active ? `${R}18` : "transparent",
              border: `1.5px solid ${i < active || complete ? "#4CAF50" : i === active ? R : "rgba(255,255,255,0.1)"}`,
              display: "flex", alignItems: "center", justifyContent: "center", fontSize: 9,
            }}>{i < active || complete ? "✓" : ""}</div>
            <div style={{ fontSize: 13, color: i === active && !complete ? "#fff" : "rgba(255,255,255,0.38)", textAlign: "left" }}>{s.label}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

