const USEFUL_TAGS = [
  { id: "matches",  emoji: "💬", label: "Get more matches" },
  { id: "attract",  emoji: "🎯", label: "Attract better people" },
  { id: "photos",   emoji: "📸", label: "Improve my photos" },
  { id: "bio",      emoji: "✍️", label: "Write a stronger bio" },
  { id: "openers",  emoji: "💡", label: "Know what to say first" },
  { id: "swipes",   emoji: "🔥", label: "Get more right-swipes" },
  { id: "dates",    emoji: "📅", label: "Turn matches into dates" },
  { id: "profile",  emoji: "✨", label: "Understand my profile" },
];

function DemandCapturePanel({ accentColor = R, onDismiss, onComplete, analysisId, source = "dateq-app" }) {
  const [step, setStep] = useState(1);
  const [email, setEmail] = useState("");
  const [legal, setLegal] = useState(false);
  const [emailErr, setEmailErr] = useState(false);
  const [legalErr, setLegalErr] = useState(false);
  const [apiErr, setApiErr] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [stars, setStars] = useState(0);
  const [hovered, setHovered] = useState(0);
  const [tags, setTags] = useState([]);

  const submitEmail = async () => {
    const emailOk = email && email.includes("@");
    if (!emailOk) { setEmailErr(true); setTimeout(() => setEmailErr(false), 2000); return; }
    if (!legal) { setLegalErr(true); setTimeout(() => setLegalErr(false), 2000); return; }

    setSubmitting(true);
    setApiErr("");
    try {
      await joinWaitlist({ email, source, analysis_id: analysisId || null });
      onComplete?.();
      setStep(2);
    } catch (err) {
      setApiErr(err.message || "Could not join the waitlist.");
    } finally {
      setSubmitting(false);
    }
  };

  const submitStars = () => {
    if (stars > 0) setStep(3);
  };

  const toggleTag = (id) => setTags((prev) => prev.includes(id) ? prev.filter((t) => t !== id) : [...prev, id]);
  const submitTags = () => setStep(4);
  const displayed = hovered || stars;

  return (
    <div style={{
      background: "rgba(14,11,11,0.97)",
      border: `1px solid ${accentColor}30`,
      borderRadius: 16,
      padding: "20px 18px",
      marginTop: 12,
      animation: "fadeUp .3s ease both",
    }}>
      {step === 1 && (
        <>
          <div style={{ fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: accentColor, fontWeight: 700, marginBottom: 8 }}>
            Join the waitlist
          </div>
          <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 22, letterSpacing: 2, marginBottom: 6 }}>
            DateQ Pro is <span style={{ color: accentColor }}>coming soon</span>
          </div>
          <p style={{ fontSize: 12, color: "rgba(255,255,255,0.38)", lineHeight: 1.65, marginBottom: 16 }}>
            Be the first to know when the full report, bio rewrite, and opener engine go live.
          </p>

          {apiErr && (
            <div style={{ marginBottom: 10, fontSize: 12, color: "#fff", background: "rgba(255,71,87,0.08)", border: "1px solid rgba(255,71,87,0.2)", borderRadius: 10, padding: "10px 12px", lineHeight: 1.6 }}>
              {apiErr}
            </div>
          )}

          <input
            type="email"
            placeholder="your@email.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && submitEmail()}
            style={{
              width: "100%", padding: "13px 14px", marginBottom: 10,
              background: "rgba(255,255,255,0.04)",
              border: `1px solid ${emailErr ? "rgba(255,71,87,0.7)" : "rgba(255,255,255,0.09)"}`,
              borderRadius: 10, color: "#fff", fontSize: 14, outline: "none",
              fontFamily: "'Plus Jakarta Sans',sans-serif", transition: "border-color .2s",
            }}
          />

          <label style={{
            display: "flex", alignItems: "flex-start", gap: 10, cursor: "pointer", marginBottom: 14,
            padding: "10px 12px", borderRadius: 10,
            background: legalErr ? "rgba(255,71,87,0.06)" : "rgba(255,255,255,0.02)",
            border: `1px solid ${legalErr ? "rgba(255,71,87,0.4)" : "rgba(255,255,255,0.06)"}`,
            transition: "all .2s",
          }}>
            <div
              onClick={() => setLegal((v) => !v)}
              style={{
                width: 18, height: 18, borderRadius: 5, flexShrink: 0, marginTop: 1,
                border: `1.5px solid ${legal ? accentColor : "rgba(255,255,255,0.2)"}`,
                background: legal ? `${accentColor}22` : "transparent",
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: 11, color: accentColor, transition: "all .15s",
              }}
            >{legal ? "✓" : ""}</div>
            <span style={{ fontSize: 11, color: "rgba(255,255,255,0.45)", lineHeight: 1.6 }}>
              Notify me when DateQ Pro launches. I agree to receive product updates and tips. <span style={{ color: "rgba(255,255,255,0.2)" }}>No spam. Unsubscribe anytime.</span>
            </span>
          </label>

          <button onClick={submitEmail} disabled={submitting} style={{
            width: "100%", padding: "13px", borderRadius: 10,
            background: accentColor, color: "#fff", border: "none", cursor: submitting ? "wait" : "pointer",
            fontSize: 14, fontWeight: 700, fontFamily: "'Plus Jakarta Sans',sans-serif",
            boxShadow: `0 8px 24px ${accentColor}35`, opacity: submitting ? 0.75 : 1,
          }}>
            {submitting ? "Joining..." : "Notify me →"}
          </button>

          {onDismiss && (
            <button onClick={onDismiss} style={{
              width: "100%", marginTop: 8, padding: "10px",
              background: "transparent", border: "none",
              color: "rgba(255,255,255,0.2)", cursor: "pointer",
              fontSize: 12, fontFamily: "'Plus Jakarta Sans',sans-serif",
            }}>Dismiss</button>
          )}
        </>
      )}

      {step === 2 && (
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: 28, marginBottom: 10 }}>🙏</div>
          <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 22, letterSpacing: 2, marginBottom: 6 }}>
            You're on the list!
          </div>
          <p style={{ fontSize: 12, color: "rgba(255,255,255,0.38)", lineHeight: 1.65, marginBottom: 20 }}>
            One quick question while you're here:
          </p>
          <div style={{ fontSize: 13, fontWeight: 700, color: "rgba(255,255,255,0.8)", marginBottom: 14 }}>
            How useful is this app?
          </div>

          <div style={{ display: "flex", justifyContent: "center", gap: 10, marginBottom: 20 }}>
            {[1, 2, 3, 4, 5].map((n) => (
              <div
                key={n}
                onClick={() => setStars(n)}
                onMouseEnter={() => setHovered(n)}
                onMouseLeave={() => setHovered(0)}
                style={{
                  fontSize: 32, cursor: "pointer",
                  filter: n <= displayed ? "grayscale(0)" : "grayscale(1) opacity(0.3)",
                  transform: n <= displayed ? "scale(1.15)" : "scale(1)",
                  transition: "all .15s",
                  userSelect: "none",
                }}
              >⭐</div>
            ))}
          </div>

          {stars > 0 && (
            <div style={{ fontSize: 12, color: "rgba(255,255,255,0.35)", marginBottom: 16 }}>
              {["", "Not useful yet", "Somewhat useful", "Pretty useful", "Very useful", "Incredibly useful"][stars]}
            </div>
          )}

          <button
            onClick={submitStars}
            disabled={stars === 0}
            style={{
              width: "100%", padding: "13px", borderRadius: 10,
              background: stars > 0 ? accentColor : "rgba(255,255,255,0.06)",
              color: stars > 0 ? "#fff" : "rgba(255,255,255,0.2)",
              border: "none", cursor: stars > 0 ? "pointer" : "not-allowed",
              fontSize: 14, fontWeight: 700, fontFamily: "'Plus Jakarta Sans',sans-serif",
              transition: "all .2s",
              boxShadow: stars > 0 ? `0 8px 24px ${accentColor}35` : "none",
            }}
          >
            {stars > 0 ? "Next →" : "Tap a star to continue"}
          </button>
        </div>
      )}

      {step === 3 && (
        <>
          <div style={{ fontSize: 13, fontWeight: 700, color: "rgba(255,255,255,0.85)", marginBottom: 6, textAlign: "center" }}>
            What would be most useful?
          </div>
          <p style={{ fontSize: 12, color: "rgba(255,255,255,0.35)", marginBottom: 16, textAlign: "center" }}>
            Select one or more
          </p>

          <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 18 }}>
            {USEFUL_TAGS.map((tag) => {
              const on = tags.includes(tag.id);
              return (
                <button
                  key={tag.id}
                  onClick={() => toggleTag(tag.id)}
                  style={{
                    display: "inline-flex", alignItems: "center", gap: 6,
                    padding: "9px 14px", borderRadius: 99, cursor: "pointer",
                    background: on ? `${accentColor}18` : "rgba(255,255,255,0.04)",
                    border: `1.5px solid ${on ? accentColor : "rgba(255,255,255,0.1)"}`,
                    color: on ? "#fff" : "rgba(255,255,255,0.45)",
                    fontSize: 12, fontWeight: on ? 700 : 500,
                    fontFamily: "'Plus Jakarta Sans',sans-serif",
                    transition: "all .15s",
                  }}
                >
                  <span style={{ fontSize: 14 }}>{tag.emoji}</span>
                  {tag.label}
                </button>
              );
            })}
          </div>

          <button
            onClick={submitTags}
            style={{
              width: "100%", padding: "13px", borderRadius: 10,
              background: accentColor, color: "#fff", border: "none", cursor: "pointer",
              fontSize: 14, fontWeight: 700, fontFamily: "'Plus Jakarta Sans',sans-serif",
              boxShadow: `0 8px 24px ${accentColor}35`,
            }}
          >
            {tags.length > 0 ? "Done →" : "Skip →"}
          </button>
        </>
      )}

      {step === 4 && (
        <div style={{ textAlign: "center", padding: "8px 0" }}>
          <div style={{ fontSize: 30, marginBottom: 10 }}>✨</div>
          <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 22, letterSpacing: 2, marginBottom: 6 }}>
            Thanks — you're in.
          </div>
          <p style={{ fontSize: 12, color: "rgba(255,255,255,0.4)", lineHeight: 1.65 }}>
            We saved your spot and your feedback.
          </p>
        </div>
      )}
    </div>
  );
}

function StickyBottomCTA({ label, icon, onClick }) {
  return (
    <div style={{
      position: "fixed",
      left: 16,
      right: 16,
      bottom: 16,
      zIndex: 120,
      display: "flex",
      justifyContent: "center",
      pointerEvents: "none",
    }}>
      <button
        onClick={onClick}
        style={{
          width: "100%",
          maxWidth: 460,
          padding: "15px 18px",
          borderRadius: 16,
          border: "1px solid rgba(255,255,255,0.1)",
          background: "rgba(14,11,11,0.96)",
          backdropFilter: "blur(18px)",
          color: "#fff",
          fontSize: 14,
          fontWeight: 700,
          fontFamily: "'Plus Jakarta Sans',sans-serif",
          boxShadow: "0 16px 40px rgba(0,0,0,0.35)",
          cursor: "pointer",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          gap: 8,
          pointerEvents: "auto",
        }}
      >
        <span style={{ fontSize: 16 }}>{icon}</span>
        <span>{label}</span>
      </button>
    </div>
  );
}


function CopyBtn({ text }) {
  const [copied, setCopied] = useState(false);
  const copy = () => {
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 1800);
    });
  };
  return (
    <button onClick={copy} style={{
      display: "flex", alignItems: "center", gap: 5,
      padding: "6px 12px", borderRadius: 8,
      background: copied ? "rgba(76,175,80,0.15)" : "rgba(255,255,255,0.05)",
      border: `1px solid ${copied ? "rgba(76,175,80,0.4)" : "rgba(255,255,255,0.1)"}`,
      color: copied ? "#4CAF50" : "rgba(255,255,255,0.45)",
      fontSize: 11, fontWeight: 600, cursor: "pointer",
      fontFamily: "'Plus Jakarta Sans',sans-serif",
      transition: "all .2s", flexShrink: 0,
    }}>
      {copied ? "✓ Copied" : "Copy"}
    </button>
  );
}

