/* ════════════════════════════════════════════════════════════════════════
   ROOT
════════════════════════════════════════════════════════════════════════ */
export default function DateQDemo() {
  const [screen, setScreen] = useState("upload");
  const [currentMode, setCurrentMode] = useState("user");
  const [returnModeAfterPro, setReturnModeAfterPro] = useState("demo");
  const [userViewData, setUserViewData] = useState(null);
  const [demoViewData, setDemoViewData] = useState(null);
  const [uploadedPreviews, setUploadedPreviews] = useState([]);
  const [loadingReady, setLoadingReady] = useState(false);
  const [loadingTarget, setLoadingTarget] = useState("freeReport");
  const [uploadError, setUploadError] = useState("");
  const [showProPreviewCTA, setShowProPreviewCTA] = useState(false);

  const currentData = currentMode === "demo" ? demoViewData : userViewData;
  const isDemo = currentMode === "demo";

  useEffect(() => () => revokePreviewUrls(uploadedPreviews), [uploadedPreviews]);

  const runDemoAnalysis = async ({ targetScreen = "freeReport", returnMode = "demo" } = {}) => {
    setUploadError("");
    setCurrentMode("demo");
    setReturnModeAfterPro(returnMode);
    setLoadingReady(false);
    setLoadingTarget(targetScreen);
    setScreen("loading");

    try {
      const result = await analyzeProfile(buildDemoPayload());
      setDemoViewData(buildViewDataFromAnalysis(result, { isDemo: true }));
    } catch {
      setDemoViewData(buildStaticDemoViewData());
    } finally {
      setLoadingReady(true);
    }
  };

  const handleAnalyzeUpload = async ({ photos, platform, bio, prompts }) => {
    const nextPreviews = photos.map((file) => ({ name: file.name, url: URL.createObjectURL(file) }));
    revokePreviewUrls(uploadedPreviews);
    setUploadedPreviews(nextPreviews);
    setShowProPreviewCTA(false);
    setUploadError("");
    setCurrentMode("user");
    setLoadingReady(false);
    setLoadingTarget("freeReport");
    setScreen("loading");

    const formData = new FormData();
    formData.append("platform", platform);
    formData.append("bio", bio || "");
    formData.append("prompts", JSON.stringify((prompts || []).filter(Boolean)));
    photos.forEach((file) => formData.append("photos", file));

    try {
      const result = await analyzeProfile(formData);
      setUserViewData(buildViewDataFromAnalysis(result, { uploadedPreviews: nextPreviews, isDemo: false }));
      setLoadingReady(true);
    } catch (err) {
      revokePreviewUrls(nextPreviews);
      setUploadedPreviews([]);
      setUploadError(err.message || DEFAULT_ANALYSIS_ERROR);
      setScreen("upload");
    }
  };

  const openDemoProReport = async () => {
    const returnMode = currentMode;
    setReturnModeAfterPro(returnMode);
    if (demoViewData) {
      setCurrentMode("demo");
      setScreen("proReport");
      return;
    }
    await runDemoAnalysis({ targetScreen: "proReport", returnMode });
  };

  const handleWaitlistJoined = () => {
    setShowProPreviewCTA(true);
  };

  const handleUpgradeClickFromPro = () => {
    setCurrentMode(returnModeAfterPro);
    setScreen("freeReport");
  };

  const reset = () => {
    revokePreviewUrls(uploadedPreviews);
    setUploadedPreviews([]);
    setScreen("upload");
    setCurrentMode("user");
    setReturnModeAfterPro("demo");
    setUserViewData(null);
    setShowProPreviewCTA(false);
    setLoadingReady(false);
    setUploadError("");
  };

  return (
    <div style={{ minHeight: "100vh", background: DARK, color: "#fff", fontFamily: "'Plus Jakarta Sans',sans-serif", overflowX: "hidden" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Plus+Jakarta+Sans:wght@300;400;500;600;700&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        ::-webkit-scrollbar { width: 3px; }
        ::-webkit-scrollbar-thumb { background: rgba(255,71,87,0.3); border-radius: 99px; }
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes fadeUp { from { opacity:0; transform:translateY(14px); } to { opacity:1; transform:translateY(0); } }
      `}</style>

      <nav style={{
        display: "flex", alignItems: "center", justifyContent: "space-between",
        padding: "16px 20px",
        borderBottom: "1px solid rgba(245,197,163,0.07)",
        background: "rgba(14,11,11,0.97)", backdropFilter: "blur(20px)",
        position: "sticky", top: 0, zIndex: 50,
      }}>
        <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 20, letterSpacing: 4, cursor: "pointer" }} onClick={reset}>
          Date<span style={{ color: R }}>Q</span>
        </div>
        {screen !== "upload" && screen !== "loading" && (
          <button onClick={reset} style={{
            background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.08)",
            color: "rgba(255,255,255,0.4)", padding: "6px 14px", borderRadius: 99,
            fontSize: 11, cursor: "pointer", fontFamily: "'Plus Jakarta Sans',sans-serif",
          }}>Back</button>
        )}
      </nav>

      <div style={{ maxWidth: 460, margin: "0 auto", padding: "36px 18px 88px" }}>
        {screen === "upload" && (
          <UploadScreen
            error={uploadError}
            onAnalyze={handleAnalyzeUpload}
            onDemo={() => { setUploadError(""); setCurrentMode("demo"); setScreen("jakePreview"); }}
          />
        )}
        {screen === "jakePreview" && <JakePreview onAnalyze={() => runDemoAnalysis({ targetScreen: "freeReport", returnMode: "demo" })} />}
        {screen === "loading" && <Loading ready={loadingReady} onDone={() => setScreen(loadingTarget)} />}
        {screen === "freeReport" && (
          <FreeReport
            data={currentData}
            isDemo={isDemo}
            onUnlockPro={() => { setReturnModeAfterPro("demo"); setCurrentMode("demo"); setScreen("proReport"); }}
            onWaitlistJoined={handleWaitlistJoined}
            onOpenProDemo={openDemoProReport}
            showProPreviewCTA={showProPreviewCTA}
            onReset={reset}
          />
        )}
        {screen === "proReport" && (
          <ProReport
            data={demoViewData || currentData}
            isDemo={true}
            onReset={reset}
            showUnlockCTA={true}
            onUpgradeClick={handleUpgradeClickFromPro}
          />
        )}
      </div>
    </div>
  );
}